package com.clashcoach.player;
import com.clashcoach.recommendation.*; import com.clashcoach.user.UserRepository; import com.fasterxml.jackson.core.*; import com.fasterxml.jackson.databind.*; import java.util.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional;
@Service public class PlayerService { private final PlayerRepository players; private final PlayerSnapshotRepository snapshots; private final UserRepository users; private final ClashApiClient clash; private final RecommendationService recommendations; private final ObjectMapper mapper; public PlayerService(PlayerRepository players,PlayerSnapshotRepository snapshots,UserRepository users,ClashApiClient clash,RecommendationService recommendations,ObjectMapper mapper){this.players=players;this.snapshots=snapshots;this.users=users;this.clash=clash;this.recommendations=recommendations;this.mapper=mapper;} @Transactional public PlayerDtos.PlayerResponse link(UUID userId,String inputTag){String tag=inputTag.trim().toUpperCase(Locale.ROOT); Player existing=players.findByUserId(userId).orElse(null); if(existing==null && players.findByPlayerTag(tag).isPresent())throw new PlayerAlreadyLinkedException(); PlayerData data=clash.getPlayer(tag); Player player=existing==null?new Player(users.getReferenceById(userId),tag,data):existing; if(existing!=null && !existing.getPlayerTag().equals(tag))throw new PlayerAlreadyLinkedException(); if(existing!=null)player.update(data); players.save(player); return saveSnapshot(player,data); } @Transactional public PlayerDtos.PlayerResponse refresh(UUID userId){Player player=findOwned(userId); return saveSnapshot(player,clash.getPlayer(player.getPlayerTag()));} @Transactional(readOnly=true) public PlayerDtos.PlayerResponse profile(UUID userId){Player player=findOwned(userId); PlayerSnapshot snapshot=snapshots.findFirstByPlayerIdOrderByCapturedAtDesc(player.getId()).orElseThrow(PlayerNotLinkedException::new);return view(player,snapshot);} @Transactional(readOnly=true) public PlayerDtos.RecommendationResponse recommendation(UUID userId){Player player=findOwned(userId); PlayerSnapshot snapshot=snapshots.findFirstByPlayerIdOrderByCapturedAtDesc(player.getId()).orElseThrow(PlayerNotLinkedException::new); Recommendation r=recommendations.find(snapshot).orElseThrow(PlayerNotLinkedException::new); try{return PlayerDtos.recommendation(r,Arrays.asList(mapper.readValue(r.getReasonCodesJson(),String[].class)));}catch(JsonProcessingException e){throw new IllegalStateException("Stored recommendation is invalid",e);}} private PlayerDtos.PlayerResponse saveSnapshot(Player player,PlayerData data){try{PlayerSnapshot snapshot=snapshots.save(new PlayerSnapshot(player,data,mapper.writeValueAsString(data.getHeroes())));recommendations.create(snapshot);return view(player,snapshot);}catch(JsonProcessingException e){throw new IllegalStateException("Unable to serialize player data",e);}} private PlayerDtos.PlayerResponse view(Player player,PlayerSnapshot snapshot){try{return PlayerDtos.player(player,snapshot,Arrays.asList(mapper.readValue(snapshot.getHeroesJson(),PlayerData.Hero[].class)));}catch(JsonProcessingException e){throw new IllegalStateException("Stored player data is invalid",e);}} private Player findOwned(UUID userId){return players.findByUserId(userId).orElseThrow(PlayerNotLinkedException::new);} public static class PlayerNotLinkedException extends RuntimeException{} public static class PlayerAlreadyLinkedException extends RuntimeException{} }
